class Solution:
 def trim(self, s: str) -> str:
 if not s:
  return s
 return s.strip();

solutions.cpp:
class Solution {
 public:
 string trim(string s) {
 if (s.empty()) {
  return s;
 } else {
  return s.substr(s.find_first_not_of(" ")); // Find the first non-whitespace character
 }
 }
 };
